class PaymentLogger {
  final bool enabled;

  const PaymentLogger(this.enabled);

  void log(String message, {Map<String, dynamic>? data}) {
    if (!enabled) return;
    debugPrint('[PaymentModule] $message ${data == null ? '' : jsonEncode(_safeData(data))}');
  }

  Map<String, dynamic> _safeData(Map<String, dynamic> data) {
    final cloned = Map<String, dynamic>.from(data);
    for (final key in cloned.keys.toList()) {
      final lower = key.toLowerCase();
      if (lower.contains('token') ||
          lower.contains('secret') ||
          lower.contains('card') ||
          lower.contains('cvv') ||
          lower.contains('pan') ||
          lower.contains('receipt')) {
        cloned[key] = 'REDACTED';
      }
    }
    return cloned;
  }
}

class SecureSigner {
  String buildIdempotencyKey({
    required String customerId,
    required String paymentReference,
    required int amountMinor,
    required String currencyCode,
  }) {
    final input = '$customerId|$paymentReference|$amountMinor|$currencyCode|${DateTime.now().toUtc().millisecondsSinceEpoch ~/ 60000}';
    return sha256.convert(utf8.encode(input)).toString();
  }
}

class PaymentHttpClient {
  final PaymentConfig config;
  final PaymentLogger logger;
  final http.Client _client;

  PaymentHttpClient({
    required this.config,
    required this.logger,
    http.Client? client,
  }) : _client = client ?? http.Client();

  Future<Map<String, dynamic>> post(
    String path, {
    required Map<String, dynamic> body,
    Map<String, String>? headers,
  }) async {
    final uri = config.gatewayBaseUrl.resolve(path);
    final requestHeaders = <String, String>{
      HttpHeaders.contentTypeHeader: 'application/json',
      HttpHeaders.acceptHeader: 'application/json',
      'X-Publishable-Key': config.publishableKey,
      'X-Api-Version': config.apiVersion,
      if (headers != null) ...headers,
    };

    logger.log('HTTP POST', data: {'uri': uri.toString(), 'body': body});

    late http.Response response;
    try {
      response = await _client
          .post(uri, headers: requestHeaders, body: jsonEncode(body))
          .timeout(config.requestTimeout);
    } on TimeoutException catch (e) {
      throw PaymentException('timeout', 'Payment request timed out', e);
    } on SocketException catch (e) {
      throw PaymentException('network_error', 'Network error during payment request', e);
    }

    final decoded = response.body.isEmpty
        ? <String, dynamic>{}
        : jsonDecode(response.body) as Map<String, dynamic>;

    logger.log('HTTP RESPONSE', data: {
      'statusCode': response.statusCode,
      'body': decoded,
    });

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw PaymentException(
        decoded['code']?.toString() ?? 'gateway_error',
        decoded['message']?.toString() ?? 'Gateway rejected request',
        decoded,
      );
    }

    return decoded;
  }

  void dispose() {
    _client.close();
  }
}

class PaymentGatewayService {
  final PaymentHttpClient httpClient;
  final PaymentLogger logger;
  final SecureSigner signer;

  PaymentGatewayService({
    required this.httpClient,
    required this.logger,
    SecureSigner? signer,
  }) : signer = signer ?? SecureSigner();

  Future<Map<String, dynamic>> createPaymentIntent({
    required String customerId,
    required PaymentItem item,
    required PaymentMethodType methodType,
    required String paymentReference,
    Map<String, dynamic> metadata = const {},
  }) async {
    final idempotencyKey = signer.buildIdempotencyKey(
      customerId: customerId,
      paymentReference: paymentReference,
      amountMinor: item.amountMinor,
      currencyCode: item.currencyCode,
    );

    return httpClient.post(
      '/payments/intents',
      headers: {'Idempotency-Key': idempotencyKey},
      body: {
        'customerId': customerId,
        'reference': paymentReference,
        'amount': item.amountMinor,
        'currency': item.currencyCode,
        'paymentMethodType': describeEnum(methodType),
        'description': item.description,
        'metadata': {
          'itemId': item.id,
          ...item.metadata,
          ...metadata,
        },
      },
    );
  }

  Future<Map<String, dynamic>> confirmPayment({
    required String paymentIntentId,
    required String paymentMethodToken,
    Map<String, dynamic> payload = const {},
  }) {
    return httpClient.post(
      '/payments/intents/$paymentIntentId/confirm',
      body: {
        'paymentMethodToken': paymentMethodToken,
        'payload': payload,
      },
    );
  }

  Future<Map<String, dynamic>> verifyStorePurchase({
    required String platform,
    required String productId,
    required String transactionId,
    required String receiptData,
  }) {
    return httpClient.post(
      '/payments/store/verify',
      body: {
        'platform': platform,
        'productId': productId,
        'transactionId': transactionId,
        'receiptData': receiptData,
      },
    );
  }

  Future<Map<String, dynamic>> refund({
    required String transactionId,
    int? amountMinor,
    String? reason,
  }) {
    return httpClient.post(
      '/payments/refunds',
      body: {
        'transactionId': transactionId,
        if (amountMinor != null) 'amount': amountMinor,
        if (reason != null) 'reason': reason,
      },
    );
  }
}

class WalletTokenizationPlatform {
  static const MethodChannel _channel = MethodChannel('payment_module/wallet');

  static Future<bool> isApplePayAvailable() async {
    if (!Platform.isIOS) return false;
    final result = await _channel.invokeMethod<bool>('isApplePayAvailable');
    return result ?? false;
  }

  static Future<bool> isGooglePayAvailable() async {
    if (!Platform.isAndroid) return false;
    final result = await _channel.invokeMethod<bool>('isGooglePayAvailable');
    return result ?? false;
  }

  static Future<Map<String, dynamic>> tokenizeApplePay({
    required PaymentConfig config,
    required PaymentItem item,
    required String countryCode,
  }) async {
    final result = await _channel.invokeMapMethod<String, dynamic>(
      'tokenizeApplePay',
      {
        'merchantId': config.merchantId,
        'merchantName': config.merchantName,
        'currencyCode': item.currencyCode,
        'countryCode': countryCode,
        'amount': item.amountMinor,
        'label': item.title,
      },
    );
    return result ?? <String, dynamic>{};
  }

  static Future<Map<String, dynamic>> tokenizeGooglePay({
    required PaymentConfig config,
    required PaymentItem item,
    required String countryCode,
  }) async {
    final result = await _channel.invokeMapMethod<String, dynamic>(
      'tokenizeGooglePay',
      {
        'merchantId': config.merchantId,
        'merchantName': config.merchantName,
        'environment': describeEnum(config.environment),
        'currencyCode': item.currencyCode,
        'countryCode': countryCode,
        'amount': item.amountMinor,
        'label': item.title,
      },
    );
    return result ?? <String, dynamic>{};
  }
}

class InAppPurchaseService {
  final InAppPurchase _iap = InAppPurchase.instance;
  final PaymentGatewayService gatewayService;
  final PaymentLogger logger;

  StreamSubscription<List<PurchaseDetails>>? _subscription;
  final StreamController<PaymentResult> _resultController = StreamController.broadcast();

  InAppPurchaseService({
    required this.gatewayService,
    required this.logger,
  });

  Stream<PaymentResult> get results => _resultController.stream;

  Future<void> initialize() async {
    final available = await _iap.isAvailable();
    if (!available) {
      throw const PaymentException('store_unavailable', 'In-app purchase store is unavailable');
    }

    _subscription ??= _iap.purchaseStream.listen(
      _handlePurchaseUpdates,
      onError: (Object error) {
        _resultController.add(
          PaymentResult(
            transactionId: '',
            status: TransactionStatus.failed,
            message: error.toString(),
          ),
        );
      },
    );
  }

  Future<List<ProductDetails>> queryProducts(Set<String> productIds) async {
    final response = await _iap.queryProductDetails(productIds);
    if (response.error != null) {
      throw PaymentException(
        response.error!.code,
        response.error!.message,
        response.error,
      );
    }
    return response.productDetails;
  }

  Future<void> purchase(ProductDetails product) async {
    final param = PurchaseParam(productDetails: product);
    await _iap.buyConsumable(purchaseParam: param, autoConsume: Platform.isAndroid);
  }

  Future<void> restorePurchases() => _iap.restorePurchases();

  Future<void> _handlePurchaseUpdates(List<PurchaseDetails> purchases) async {
    for (final purchase in purchases) {
      try {
        if (purchase.status == PurchaseStatus.pending) {
          _resultController.add(
            PaymentResult(
              transactionId: purchase.purchaseID ?? '',
              status: TransactionStatus.pending,
              message: 'Purchase pending',
            ),
          );
          continue;
        }

        if (purchase.status == PurchaseStatus.error) {
          _resultController.add(
            PaymentResult(
              transactionId: purchase.purchaseID ?? '',
              status: TransactionStatus.failed,
              message: purchase.error?.message ?? 'Purchase failed',
              raw: {
                'code': purchase.error?.code,
                'source': purchase.error?.source,
              },
            ),
          );
          if (purchase.pendingCompletePurchase) {
            await _iap.completePurchase(purchase);
          }
          continue;
        }

        if (purchase.status == PurchaseStatus.canceled) {
          _resultController.add(
            PaymentResult(
              transactionId: purchase.purchaseID ?? '',
              status: TransactionStatus.cancelled,
              message: 'Purchase cancelled',
            ),
          );
          if (purchase.pendingCompletePurchase) {
            await _iap.completePurchase(purchase);
          }
          continue;
        }

        if (purchase.status == PurchaseStatus.purchased ||
            purchase.status == PurchaseStatus.restored) {
          final verification = await gatewayService.verifyStorePurchase(
            platform: Platform.isIOS ? 'ios' : 'android',
            productId: purchase.productID,
            transactionId: purchase.purchaseID ?? '',
            receiptData: purchase.verificationData.serverVerificationData,
          );

          final verified = verification['verified'] == true;
          final transactionId =
              verification['transactionId']?.toString() ?? purchase.purchaseID ?? '';

          _resultController.add(
            PaymentResult(
              transactionId: transactionId,
              status: verified ? TransactionStatus.captured : TransactionStatus.failed,
              message: verified ? 'Purchase verified' : 'Purchase verification failed',
              receipt: purchase.verificationData.serverVerificationData,
              raw: verification,
            ),
          );
        }

        if (purchase.pendingCompletePurchase) {
          await _iap.completePurchase(purchase);
        }
      } catch (e) {
        _resultController.add(
          PaymentResult(
            transactionId: purchase.purchaseID ?? '',
            status: TransactionStatus.failed,
            message: e.toString(),
          ),
        );
      }
    }
  }

  Future<void> dispose() async {
    await _subscription?.cancel();
    await _resultController.close();
  }
}

class MobileWalletService {
  final PaymentConfig config;
  final PaymentGatewayService gatewayService;
  final PaymentLogger logger;

  MobileWalletService({
    required this.config,
    required this.gatewayService,
    required this.logger,
  });

  Future<bool> isAvailable(MobileWalletProvider provider) {
    switch (provider) {
      case MobileWalletProvider.applePay:
        return WalletTokenizationPlatform.isApplePayAvailable();
      case MobileWalletProvider.googlePay:
        return WalletTokenizationPlatform.isGooglePayAvailable();
    }
  }

  Future<PaymentResult> payWithWallet({
    required MobileWalletProvider provider,
    required String customerId,
    required PaymentItem item,
    required String paymentReference,
    required String countryCode,
    Map<String, dynamic> metadata = const {},
  }) async {
    final methodType = provider == MobileWalletProvider.applePay
        ? PaymentMethodType.applePay
        : PaymentMethodType.googlePay;

    final intent = await gatewayService.createPaymentIntent(
      customerId: customerId,
      item: item,
      methodType: methodType,
      paymentReference: paymentReference,
      metadata: metadata,
    );

    final intentId = intent['id']?.toString();
    if (intentId == null || intentId.isEmpty) {
      throw const PaymentException('invalid_intent', 'Missing payment intent ID');
    }

    final tokenPayload = provider == MobileWalletProvider.applePay
        ? await WalletTokenizationPlatform.tokenizeApplePay(
            config: config,
            item: item,
            countryCode: countryCode,
          )
        : await WalletTokenizationPlatform.tokenizeGooglePay(
            config: config,
            item: item,
            countryCode: countryCode,
          );

    final paymentMethodToken = tokenPayload['token']?.toString();
    if (paymentMethodToken == null || paymentMethodToken.isEmpty) {
      throw const PaymentException('tokenization_failed', 'Wallet tokenization failed');
    }

    final confirmation = await gatewayService.confirmPayment(
      paymentIntentId: intentId,
      paymentMethodToken: paymentMethodToken,
      payload: {
        'walletProvider': describeEnum(provider),
        'walletData': tokenPayload,
      },
    );

    return PaymentResult(
      transactionId: confirmation['transactionId']?.toString() ?? intentId,
      status: _mapStatus(confirmation['status']?.toString()),
      message: confirmation['message']?.toString() ?? 'Payment processed',
      raw: confirmation,
    );
  }

  TransactionStatus _mapStatus(String? value) {
    switch (value) {
      case 'authorized':
        return TransactionStatus.authorized;
      case 'captured':
        return TransactionStatus.captured;
      case 'requires_action':
        return TransactionStatus.requiresAction;
      case 'pending':
        return TransactionStatus.pending;
      case 'cancelled':
        return TransactionStatus.cancelled;
      case 'refunded':
        return TransactionStatus.refunded;
      case 'failed':
      default:
        return TransactionStatus.failed;
    }
  }
}

class PaymentProcessor {
  final PaymentConfig config;
  final PaymentLogger logger;
  late final PaymentHttpClient _httpClient;
  late final PaymentGatewayService gateway;
  late final InAppPurchaseService inAppPurchase;
  late final MobileWalletService wallet;

  PaymentProcessor({
    required this.config,
  }) : logger = PaymentLogger(config.enableLogging) {
    _httpClient = PaymentHttpClient(config: config, logger: logger);
    gateway = PaymentGatewayService(httpClient: _httpClient, logger: logger);
    inAppPurchase = InAppPurchaseService(gatewayService: gateway, logger: logger);
    wallet = MobileWalletService(
      config: config,
      gatewayService: gateway,
      logger: logger,
    );
  }

  Future<void> initialize() async {
    await inAppPurchase.initialize();
  }

  Future<List<ProductDetails>> getStoreProducts(List<PaymentItem> items) async {
    final productIds = items
        .where((e) => e.storeProductId != null && e.storeProductId!.isNotEmpty)
        .map((e) => e.storeProductId!)
        .toSet();

    if (productIds.isEmpty) return const [];
    return inAppPurchase.queryProducts(productIds);
  }

  Future<void> purchaseInAppProduct(ProductDetails product) {
    return inAppPurchase.purchase(product);
  }

  Stream<PaymentResult> get inAppPurchaseResults => inAppPurchase.results;

  Future<PaymentResult> payWithApplePay({
    required String customerId,
    required PaymentItem item,
    required String paymentReference,
    required String countryCode,
    Map<String, dynamic> metadata = const {},
  }) {
    if (!Platform.isIOS) {
      throw const PaymentException('unsupported_platform', 'Apple Pay is only supported on iOS');
    }
    return wallet.payWithWallet(
      provider: MobileWalletProvider.applePay,
      customerId: customerId,
      item: item,
      paymentReference: paymentReference,
      countryCode: countryCode,
      metadata: metadata,
    );
  }

  Future<PaymentResult> payWithGooglePay({
    required String customerId,
    required PaymentItem item,
    required String paymentReference,
    required String countryCode,
    Map<String, dynamic> metadata = const {},
  }) {
    if (!Platform.isAndroid) {
      throw const PaymentException('unsupported_platform', 'Google Pay is only supported on Android');
    }
    return wallet.payWithWallet(
      provider: MobileWalletProvider.googlePay,
      customerId: customerId,
      item: item,
      paymentReference: paymentReference,
      countryCode: countryCode,
      metadata: metadata,
    );
  }

  Future<Map<String, dynamic>> createServerSideCardPaymentIntent({
    required String customerId,
    required PaymentItem item,
    required String paymentReference,
    Map<String, dynamic> metadata = const {},
  }) {
    return gateway.createPaymentIntent(
      customerId: customerId,
      item: item,
      methodType: PaymentMethodType.cardTokenized,
      paymentReference: paymentReference,
      metadata: metadata,
    );
  }

  Future<Map<String, dynamic>> refund({
    required String transactionId,
    int? amountMinor,
    String? reason,
  }) {
    return gateway.refund(
      transactionId: transactionId,
      amountMinor: amountMinor,
      reason: reason,
    );
  }

  Future<void> dispose() async {
    await inAppPurchase.dispose();
    _httpClient.dispose();
  }
}

